"use client";
import { useEffect, useState } from "react";

interface OfferLetter {
  name: string;
  url: string;
}

export default function Dashboard() {
  const [offerLetters, setOfferLetters] = useState<OfferLetter[]>([]);

  const router;

  useEffect(() => {
    fetch("/api/offer-letter")
      .then((res) => res.json())
      .then((data) => {
        console.log(data);
        setOfferLetters(data.offerLetters);
        
      })
      .catch((err) => console.error("Error fetching offer letters:", err));
  }, []);

  return (
    <div className="container mx-auto p-6">
      <h1 className="text-2xl font-semibold mb-4">Offer Letters</h1>
      <table className="min-w-full bg-white shadow-md rounded-lg">
        <thead>
          <tr className="bg-gray-200 text-gray-700">
            <th className="p-3 text-left">File Name</th>
            <th className="p-3 text-left">Actions</th>
          </tr>
        </thead>
        <tbody>
          {offerLetters.map((file, index) => (
            <tr key={index} className="border-b">
              <td className="p-3">{file.name}</td>
              <td className="p-3">
                <a
                  href={file.url}
                  target="_blank"
                  className="text-blue-500 hover:underline"
                >
                  View
                </a>
                <span className="mx-2">|</span>
                <a
                  href={file.url}
                  download={file.name}
                  className="text-green-500 hover:underline"
                >
                  Download
                </a>
                <span className="mx-2">|</span>
                <a onClick={() => router.push("/payment")}
                  className="text-green-500 hover:underline"
                >
                  Payment
                </a>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
